    private fun setupActivityResultLaunchers() {
        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                val data = result.data
                if (data?.data != null) {
                    fileUploadCallback?.onReceiveValue(arrayOf(data.data!!))
                } else if (cameraImageUri != null) {
                    fileUploadCallback?.onReceiveValue(arrayOf(cameraImageUri!!))
                } else {
                    fileUploadCallback?.onReceiveValue(null)
                }
            } else {
                fileUploadCallback?.onReceiveValue(null)
            }
            fileUploadCallback = null
        }

        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestMultiplePermissions()
        ) { permissions ->
            val allGranted = permissions.values.all { it }
            if (allGranted) {
                webView.evaluateJavascript(
                    "javascript:window.onNativeCameraPermissionResult(true)", null
                )
            } else {
                webView.evaluateJavascript(
                    "javascript:window.onNativeCameraPermissionResult(false)", null
                )
            }
        }

        notificationPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            webView.evaluateJavascript(
                "javascript:window.onNativeNotificationPermissionResult($isGranted)", null
            )
        }
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        webView = findViewById(R.id.webView)

        // Configure WebView settings
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            mediaPlaybackRequiresUserGesture = false
            mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
            cacheMode = WebSettings.LOAD_DEFAULT
            setSupportZoom(true)
            builtInZoomControls = true
            displayZoomControls = false
            useWideViewPort = true
            loadWithOverviewMode = true
            javaScriptCanOpenWindowsAutomatically = true

            // Enable app cache
            val cachePath = applicationContext.cacheDir.absolutePath
            setGeolocationEnabled(true)
        }

        // Add JavaScript interface bridge
        webView.addJavascriptInterface(NativeBridge(this), "NativeBridge")

        // Set WebViewClient
        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(
                view: WebView?,
                request: WebResourceRequest?
            ): Boolean {
                val url = request?.url?.toString() ?: return false

                // Handle external links
                return if (url.startsWith("http://") || url.startsWith("https://")) {
                    if (url.contains("your-webapp-url.com")) { // Keep navigation within your domain
                        false
                    } else {
                        // Open external links in browser
                        startActivity(Intent(Intent.ACTION_VIEW, Uri.parse(url)))
                        true
                    }
                } else {
                    // Handle custom schemes (tel:, mailto:, etc.)
                    try {
                        startActivity(Intent(Intent.ACTION_VIEW, Uri.parse(url)))
                    } catch (e: Exception) {
                        Log.e(TAG, "Cannot handle URL: $url", e)
                    }
                    true
                }
            }

            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
                Log.d(TAG, "Page loading started: $url")
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                Log.d(TAG, "Page loading finished: $url")
                // Inject any initialization JavaScript
                injectBridgeInitScript()
            }

            override fun onReceivedError(
                view: WebView?,
                request: WebResourceRequest?,
                error: WebResourceError?
            ) {
                super.onReceivedError(view, request, error)
                if (request?.isForMainFrame == true) {
                    Log.e(TAG, "Error loading page: ${error?.description}")
                    // Load offline fallback page
                    view?.loadData(
                        getOfflineHtml(),
                        "text/html",
                        "UTF-8"
                    )
                }
            }
        }

        // Set WebChromeClient for file uploads and permissions
        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                fileUploadCallback?.onReceiveValue(null)
                fileUploadCallback = filePathCallback

                val intent = fileChooserParams?.createIntent()
                try {
                    // Create camera intent
                    val cameraIntent = createCameraIntent()

                    // Create chooser with camera option
                    val chooserIntent = Intent.createChooser(intent, "Select Source")
                    if (cameraIntent != null) {
                        chooserIntent.putExtra(
                            Intent.EXTRA_INITIAL_INTENTS,
                            arrayOf(cameraIntent)
                        )
                    }
                    fileChooserLauncher.launch(chooserIntent)
                } catch (e: Exception) {
                    fileUploadCallback = null
                    Log.e(TAG, "File chooser error", e)
                    return false
                }
                return true
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                runOnUiThread {
                    request?.grant(request.resources)
                }
            }

            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                Log.d(
                    TAG,
                    "WebView Console: ${consoleMessage?.message()} -- Line ${consoleMessage?.lineNumber()}"
                )
                return true
            }
        }

        // Load the web app
        webView.loadUrl(WEB_APP_URL)
    }

    private fun injectBridgeInitScript() {
        val script = """
            (function() {
                if (window.NativeBridgeReady) return;
                window.NativeBridgeReady = true;
                
                // Dispatch event to notify web app that native bridge is ready
                window.dispatchEvent(new CustomEvent('NativeBridgeReady', {
                    detail: { platform: 'android' }
                }));
                
                console.log('NativeBridge initialized for Android');
            })();
        """.trimIndent()
        webView.evaluateJavascript(script, null)
    }

    private fun createCameraIntent(): Intent? {
        return try {
            val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
            val imageFileName = "IMG_${timeStamp}"

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                val contentValues = ContentValues().apply {
                    put(MediaStore.Images.Media.DISPLAY_NAME, "$imageFileName.jpg")
                    put(MediaStore.Images.Media.MIME_TYPE, "image/jpeg")
                    put(
                        MediaStore.Images.Media.RELATIVE_PATH,
                        Environment.DIRECTORY_PICTURES + "/HybridApp"
                    )
                }
                cameraImageUri = contentResolver.insert(
                    MediaStore.Images.Media.EXTERNAL_CONTENT_URI,
                    contentValues
                )
            } else {
                val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
                val imageFile = File.createTempFile(imageFileName, ".jpg", storageDir)
                cameraImageUri = FileProvider.getUriForFile(
                    this,
                    "${applicationContext.packageName}.fileprovider",
                    imageFile
                )
            }

            Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error creating camera intent", e)
            null
        }
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "App Notifications",
                NotificationManager.IMPORTANCE_HIGH
            ).apply {
                description = "Notifications from the hybrid app"
                enableVibration(true)
            }
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

