    // ==========================================
    // Native Bridge - JavaScript Interface
    // ==========================================
    inner class NativeBridge(private val activity: Activity) {

        private val prefs: SharedPreferences =
            activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        // --- Camera Functions ---

        @JavascriptInterface
        fun requestCameraPermission() {
            activity.runOnUiThread {
                val permissions = mutableListOf(Manifest.permission.CAMERA)
                if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q) {
                    permissions.add(Manifest.permission.WRITE_EXTERNAL_STORAGE)
                    permissions.add(Manifest.permission.READ_EXTERNAL_STORAGE)
                }

                val allGranted = permissions.all {
                    ContextCompat.checkSelfPermission(activity, it) ==
                            PackageManager.PERMISSION_GRANTED
                }

                if (allGranted) {
                    webView.evaluateJavascript(
                        "javascript:window.onNativeCameraPermissionResult(true)", null
                    )
                } else {
                    cameraPermissionLauncher.launch(permissions.toTypedArray())
                }
            }
        }

        @JavascriptInterface
        fun hasCameraPermission(): Boolean {
            return ContextCompat.checkSelfPermission(
                activity, Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED
        }

        @JavascriptInterface
        fun openCamera() {
            activity.runOnUiThread {
                if (hasCameraPermission()) {
                    val cameraIntent = createCameraIntent()
                    if (cameraIntent != null) {
                        try {
                            fileChooserLauncher.launch(cameraIntent)
                        } catch (e: Exception) {
                            Log.e(TAG, "Error opening camera", e)
                            webView.evaluateJavascript(
                                "javascript:window.onNativeCameraError('${e.message}')", null
                            )
                        }
                    }
                } else {
                    requestCameraPermission()
                }
            }
        }

        @JavascriptInterface
        fun capturePhoto(callbackName: String) {
            activity.runOnUiThread {
                if (!hasCameraPermission()) {
                    webView.evaluateJavascript(
                        "javascript:$callbackName({success: false, error: 'Camera permission not granted'})",
                        null
                    )
                    return@runOnUiThread
                }

                try {
                    val timeStamp =
                        SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
                    val imageFileName = "IMG_${timeStamp}"

                    val storageDir = activity.getExternalFilesDir(Environment.DIRECTORY_PICTURES)
                    val imageFile = File.createTempFile(imageFileName, ".jpg", storageDir)
                    val photoUri = FileProvider.getUriForFile(
                        activity,
                        "${activity.applicationContext.packageName}.fileprovider",
                        imageFile
                    )
                    cameraImageUri = photoUri

                    // Store callback and launch camera
                    fileUploadCallback?.onReceiveValue(null)
                    fileUploadCallback = null

                    val cameraResultLauncher = registerForActivityResult(
                        ActivityResultContracts.StartActivityForResult()
                    ) { result ->
                        if (result.resultCode == Activity.RESULT_OK) {
                            webView.evaluateJavascript(
                                "javascript:$callbackName({success: true, uri: '${photoUri}'})",
                                null
                            )
                        } else {
                            webView.evaluateJavascript(
                                "javascript:$callbackName({success: false, error: 'Camera cancelled'})",
                                null
                            )
                        }
                    }

                    val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                        putExtra(MediaStore.EXTRA_OUTPUT, photoUri)
                    }
                    cameraResultLauncher.launch(intent)

                } catch (e: Exception) {
                    Log.e(TAG, "Error capturing photo", e)
                    webView.evaluateJavascript(
                        "javascript:$callbackName({success: false, error: '${e.message}'})",
                        null
                    )
                }
            }
        }

        // --- Local Storage Functions ---

        @JavascriptInterface
        fun saveToLocalStorage(key: String, value: String): Boolean {
            return try {
                prefs.edit().putString(key, value).apply()
                true
            } catch (e: Exception) {
                Log.e(TAG, "Error saving to local storage", e)
                false
            }
        }

        @JavascriptInterface
        fun getFromLocalStorage(key: String): String? {
            return try {
                prefs.getString(key, null)
            } catch (e: Exception) {
                Log.e(TAG, "Error reading from local storage", e)
                null
            }
        }

        @JavascriptInterface
        fun removeFromLocalStorage(key: String): Boolean {
            return try {
                prefs.edit().remove(key).apply()
                true
            } catch (e: Exception) {
                Log.e(TAG, "Error removing from local storage", e)
                false
            }
        }

        @JavascriptInterface
        fun clearLocalStorage(): Boolean {
            return try {
                prefs.edit().clear().apply()
                true
            } catch (e: Exception) {
                Log.e(TAG, "Error clearing local storage", e)
                false
            }
        }

        @JavascriptInterface
        fun getAllLocalStorageKeys(): String {
            return try {
                val keys = prefs.all.keys.toList()
                JSONObject().apply {
                    put("keys", org.json.JSONArray(keys))
                }.toString()
            } catch (e: Exception) {
                Log.e(TAG, "Error getting all keys", e)
                "{\"keys\":[]}"
            }
        }

        @JavascriptInterface
        fun saveSecureData(key: String, value: String): Boolean {
            // For production, use EncryptedSharedPreferences
            return try {
                val securePrefs = activity.getSharedPreferences(
                    "${PREFS_NAME}_secure", Context.MODE_PRIVATE
                )
                securePrefs.edit().putString(key, value).apply()
                true
            } catch (e: Exception) {
                Log.e(TAG, "Error saving secure data", e)
                false
            }
        }

        @JavascriptInterface
        fun getSecureData(key: String): String? {
            return try {
                val securePrefs = activity.getSharedPreferences(
                    "${PREFS_NAME}_secure", Context.MODE_PRIVATE
                )
                securePrefs.getString(key, null)
            } catch (e: Exception) {
                Log.e(TAG, "Error reading secure data", e)
                null
            }
        }

        // --- Push Notification Functions ---

        @JavascriptInterface
        fun requestNotificationPermission() {
            activity.runOnUiThread {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                    if (ContextCompat.checkSelfPermission(
                            activity,
                            Manifest.permission.POST_NOTIFICATIONS
                        ) != PackageManager.PERMISSION_GRANTED
                    ) {
                        notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                    } else {
                        webView.evaluateJavascript(
                            "javascript:window.onNativeNotificationPermissionResult(true)", null
                        )
                    }
                } else {
                    webView.evaluateJavascript(
                        "javascript:window.onNativeNotificationPermissionResult(true)", null
                    )
                }
            }
        }

        @JavascriptInterface
        fun hasNotificationPermission(): Boolean {
            return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                ContextCompat.checkSelfPermission(
                    activity, Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED
            } else {
                NotificationManagerCompat.from(activity).areNotificationsEnabled()
            }
        }

        @JavascriptInterface
        fun showLocalNotification(title: String, body: String, notificationId: Int) {
            activity.runOnUiThread {
                try {
                    val builder = NotificationCompat.Builder(activity, NOTIFICATION_CHANNEL_ID)
                        .setSmallIcon(android.R.drawable.ic_dialog_info)
                        .setContentTitle(title)
                        .setContentText(body)
                        .setPriority(NotificationCompat.PRIORITY_HIGH)
                        .setAutoCancel(true)

                    if (ActivityCompat.checkSelfPermission(
                            activity,
                            Manifest.permission.POST_NOTIFICATIONS
                        ) == PackageManager.PERMISSION_GRANTED ||
                        Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU
                    ) {
                        NotificationManagerCompat.from(activity)
                            .notify(notificationId, builder.build())
                        webView.evaluateJavascript(
                            "javascript:window.onNativeNotificationShown($notificationId)", null
                        )
                    } else {
                        webView.evaluateJavascript(
                            "javascript:window.onNativeNotificationError('Permission not granted')",
                            null
                        )
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "Error showing notification", e)
                    webView.evaluateJavascript(
                        "javascript:window.onNativeNotificationError('${e.message}')", null
                    )
                }
            }
        }

        @JavascriptInterface
        fun showLocalNotificationWithData(
            title: String,
            body: String,
            notificationId: Int,
            dataJson: String
        ) {
            activity.runOnUiThread {
                try {
                    val data = JSONObject(dataJson)

                    val builder = NotificationCompat.Builder(activity, NOTIFICATION_CHANNEL_ID)
                        .setSmallIcon(android.R.drawable.ic_dialog_info)
                        .setContentTitle(title)
                        .setContentText(body)
                        .setPriority(NotificationCompat.PRIORITY_HIGH)
                        .setAutoCancel(true)

                    // Add big text style if body is long
                    if (body.length > 40) {
                        builder.setStyle(NotificationCompat.BigTextStyle().bigText(body))
                    }

                    if (ActivityCompat.checkSelfPermission(
                            activity,
                            Manifest.permission.POST_NOTIFICATIONS
                        ) == PackageManager.PERMISSION_GRANTED ||
                        Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU
                    ) {
                        NotificationManagerCompat.from(activity)
                            .notify(notificationId, builder.build())
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "Error showing notification with data", e)
                }
            }
        }

        @JavascriptInterface
        fun cancelNotification(notificationId: Int) {
            NotificationManagerCompat.from(activity).cancel(notificationId)
        }

        @JavascriptInterface
        fun cancelAllNotifications() {
            NotificationManagerCompat.from(activity).cancelAll()
        }

        @JavascriptInterface
        fun getFCMToken(): String {
