        @JavascriptInterface
        fun openExternalUrl(url: String) {
            activity.runOnUiThread {
                try {
                    val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                    activity.startActivity(intent)
                } catch (e: Exception) {
                    Log.e(TAG, "Error opening external URL", e)
                }
            }
        }

        @JavascriptInterface
        fun vibrate(durationMs: Long) {
            activity.runOnUiThread {
                try {
                    val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                        val vibratorManager =
                            activity.getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as android.os.VibratorManager
                        vibratorManager.defaultVibrator
                    } else {
                        @Suppress("DEPRECATION")
                        activity.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
                    }

                    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                        vibrator.vibrate(
                            android.os.VibrationEffect.createOneShot(
                                durationMs,
                                android.os.VibrationEffect.DEFAULT_AMPLITUDE
                            )
                        )
                    } else {
                        @Suppress("DEPRECATION")
                        vibrator.vibrate(durationMs)
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "Error vibrating", e)
                }
            }
        }

        @JavascriptInterface
        fun log(level: String, message: String) {
            when (level.lowercase()) {
                "debug" -> Log.d(TAG, "JS: $message")
                "info" -> Log.i(TAG, "JS: $message")
                "warn" -> Log.w(TAG, "JS: $message")
                "error" -> Log.e(TAG, "JS: $message")
                else -> Log.d(TAG, "JS: $message")
            }
        }
    }
}